sql:
SELECT history_id, session_id, change_description, change_date 
FROM session_history
WHERE change_type = 'update';

SELECT session_id, detail_description, detail_category
FROM session_details
WHERE detail_category = 'bills';

external_knowledge:
; A session refers to a period of time when the legislative body is in session, with a unique session ID; 
; Leadership title and leader name are used to identify the leaders of the sessions; 
; The district ID and party ID are used to identify the district and party affiliation of the session leaders; 
; Committee counts and rankings are used to analyze the number and importance of committees within each session; 
; Bill statistics are used to analyze the voting patterns within each session.

sql:
WITH LeadershipChanges AS (
    SELECT l.leader_name, COUNT(sh.history_id) AS change_count
    FROM session_history sh
    JOIN leadership l ON sh.session_id = l.session_id
    GROUP BY l.leader_name
),
TopLeader AS (
    SELECT leader_name, change_count
    FROM LeadershipChanges
    WHERE change_count = (
        SELECT MAX(change_count) FROM LeadershipChanges
    )
),
SessionWithComponents AS (
    SELECT s.session_id
    FROM sessions s
    WHERE EXISTS (
        SELECT 1 FROM resolutions r WHERE r.session_id = s.session_id
    )
    AND EXISTS (
        SELECT 1 FROM bills b WHERE b.session_id = s.session_id
    )
    AND EXISTS (
        SELECT 1 FROM committee_members cm WHERE cm.committee_id IN (
            SELECT c.committee_id FROM committees c WHERE c.session_id = s.session_id
        )
    )
    AND EXISTS (
        SELECT 1 FROM votes v WHERE v.bill_id IN (
            SELECT b.bill_id FROM bills b WHERE b.session_id = s.session_id
        )
    )
)
SELECT tl.leader_name AS MostSignificantLeader
FROM TopLeader tl
WHERE tl.leader_name IN (
    SELECT DISTINCT l.leader_name
    FROM leadership l
    JOIN SessionWithComponents swc ON l.session_id = swc.session_id
);
